using System.Net.Http;
using Microsoft.AspNetCore.HttpOverrides;

var builder = WebApplication.CreateBuilder(args);
builder.Services.AddScoped<IUserService, UserService>();

// FIX [ValidateScopes]: Changed from AddSingleton to AddScoped.
// .NET 9 enables ValidateScopes in development by default. A singleton that
// resolves a scoped service (IUserService) now throws at startup.
builder.Services.AddScoped<ICacheService>(sp =>
    new CacheService(sp.GetRequiredService<IUserService>()));

// FIX [SocketsHttpHandler]: The default primary handler is now SocketsHttpHandler.
// Casting to HttpClientHandler throws InvalidCastException. Handle both types.
builder.Services.AddHttpClient("api")
    .ConfigureHttpMessageHandlerBuilder(b =>
    {
        if (b.PrimaryHandler is HttpClientHandler hch) hch.UseCookies = false;
        else if (b.PrimaryHandler is SocketsHttpHandler shh) shh.UseCookies = false;
    });

// FIX [Header redaction]: .NET 9 redacts all header values in Trace-level
// HttpClientFactory logs by default. Allowlist non-sensitive headers you need
// to inspect during debugging.
builder.Services.ConfigureHttpClientDefaults(b =>
    b.RedactLoggedHeaders(header =>
        header != "X-Request-Id"
        && header != "X-Correlation-Id"
        && header != "Cache-Control"
        && header != "Accept"
        && header != "Content-Type"));

// FIX [ForwardedHeaders]: .NET 9 now ignores X-Forwarded-* headers from proxies
// not in KnownProxies or KnownNetworks. Add your reverse proxy address here.
builder.Services.Configure<ForwardedHeadersOptions>(options =>
{
    options.ForwardedHeaders = ForwardedHeaders.XForwardedFor;
    // TODO: Replace with your actual reverse proxy IP address.
    options.KnownProxies.Add(System.Net.IPAddress.Parse("10.0.0.1"));
});

var app = builder.Build();
app.UseForwardedHeaders();
app.Run();

